const input = $input.first().json;
const body = input.body || input;
const instruction = (body.instruction || body.text || '').trim();

if (!instruction) {
  return [{ json: { error: '기획안 지시가 비어있습니다.', success: false } }];
}

let prdType = 'product-detail';
let typeName = '상품 상세페이지';

const lower = instruction.toLowerCase();
if (/이벤트|할인|프로모션|기획전|쿠폰/.test(lower)) {
  prdType = 'event-promo';
  typeName = '이벤트/프로모션';
} else if (/랜딩|모집|소개|브랜드페이지/.test(lower)) {
  prdType = 'landing-page';
  typeName = '랜딩 페이지';
} else if (/인스타|유튜브|블로그|sns|릴스|숏츠|포스트/.test(lower)) {
  prdType = 'sns-content';
  typeName = 'SNS 콘텐츠';
} else if (/상세페이지|상품|신상품/.test(lower)) {
  prdType = 'product-detail';
  typeName = '상품 상세페이지';
}

const topic = instruction.replace(/^기획안\s*/, '').replace(/^(상세페이지|이벤트|할인|프로모션|랜딩|인스타|유튜브|블로그|SNS|릴스)\s*/, '').trim() || instruction;
const requestedBy = body.requested_by || body.user || '대표';
const now = new Date();
const kstDate = new Date(now.getTime() + 9 * 60 * 60 * 1000).toISOString().slice(0, 10);

return [{
  json: { instruction, prdType, typeName, topic, requestedBy, kstDate, success: true }
}];

const input = $input.first().json;
const prev = $('입력 파싱').first().json;

let content = '';
if (input.choices && input.choices[0]) {
  content = input.choices[0].message.content || '';
} else if (input.content && Array.isArray(input.content)) {
  content = input.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

const titleMatch = content.match(/^##\s+(.+)/m);
const title = titleMatch ? titleMatch[1].trim() : prev.topic;

return [{
  json: {
    title,
    prd_type: prev.prdType,
    type_name: prev.typeName,
    instruction: prev.instruction,
    content_md: content,
    requested_by: prev.requestedBy,
    status: 'draft',
    created_date: prev.kstDate
  }
}];

const prd = $('기획안 텍스트 추출').first().json;
const nocoResult = $input.first().json;
const rowId = nocoResult.Id || nocoResult.id || '?';

const preview = prd.content_md.slice(0, 500).replace(/[<>&]/g, c => ({'<':'&lt;','>':'&gt;','&':'&amp;'}[c]));

const msg = [
  '<b>[기획안 생성 완료]</b>',
  '',
  `<b>제목</b>: \${prd.title}`,
  `<b>유형</b>: \${prd.type_name}`,
  `<b>요청</b>: \${prd.instruction}`,
  `<b>상태</b>: draft (승인 대기)`,
  `<b>NocoDB ID</b>: #\${rowId}`,
  '',
  '<b>미리보기</b>:',
  `<pre>\${preview}...</pre>`,
  '',
  '승인하려면 "기획안 승인 #' + rowId + '"이라고 답해주세요.',
  '담당자 지정: "기획안 배정 #' + rowId + ' 다경" 또는 "승해"'
].join('\n');

return [{ json: { message: msg, rowId } }];

const input = $input.first().json;
const body = input.body || input;
const text = (body.text || body.instruction || '').trim();

// 패턴: "기획안 승인 #123" 또는 "기획안 배정 #123 다경"
const approveMatch = text.match(/기획안\s*승인\s*#?(\d+)/);
const assignMatch = text.match(/기획안\s*배정\s*#?(\d+)\s+(.+)/);

if (approveMatch) {
  return [{ json: { action: 'approve', rowId: parseInt(approveMatch[1]), assignee: null } }];
} else if (assignMatch) {
  return [{ json: { action: 'assign', rowId: parseInt(assignMatch[1]), assignee: assignMatch[2].trim() } }];
} else {
  return [{ json: { action: 'unknown', error: '인식할 수 없는 명령입니다. 예: 기획안 승인 #1 / 기획안 배정 #1 다경' } }];
}

const { action, rowId, assignee } = $input.first().json;
const now = new Date();
const kstDate = new Date(now.getTime() + 9 * 60 * 60 * 1000).toISOString().slice(0, 10);

const patchBody = {};
if (action === 'approve') {
  patchBody.status = 'approved';
  patchBody.approved_date = kstDate;
} else if (action === 'assign') {
  patchBody.status = 'assigned';
  patchBody.assignee = assignee;
}

return [{ json: { rowId, patchBody, action, assignee } }];

const prev = $('PATCH 데이터 구성').first().json;
const result = $input.first().json;
const title = result.title || '기획안';

let msg = '';
if (prev.action === 'approve') {
  msg = `<b>[기획안 승인 완료]</b>

<b>제목</b>: \${title}
<b>NocoDB ID</b>: #\${prev.rowId}
<b>상태</b>: approved

담당자를 배정하려면:
"기획안 배정 #\${prev.rowId} 다경" 또는 "승해"`;
} else if (prev.action === 'assign') {
  msg = `<b>[기획안 배정 완료]</b>

<b>제목</b>: \${title}
<b>NocoDB ID</b>: #\${prev.rowId}
<b>담당자</b>: \${prev.assignee}
<b>상태</b>: assigned

\${prev.assignee}님에게 디자인 브리프가 전달됩니다.`;
}

return [{ json: { message: msg, assignee: prev.assignee, action: prev.action, rowId: prev.rowId } }];
